import React, { useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { authAPI } from "../services/api";

export default function OAuthCallback() {
  const [params] = useSearchParams();
  const { login } = useAuth();
  const nav = useNavigate();

  useEffect(() => {
    const token = params.get("token");
    const error = params.get("error");
    if (error) { nav("/login?error=oauth"); return; }
    if (token) {
      localStorage.setItem("sg_token", token);
      authAPI.profile()
        .then(r => { login(r.data.user, token); nav("/dashboard"); })
        .catch(() => nav("/login"));
    } else {
      nav("/login");
    }
  }, []);

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg)", display:"flex", alignItems:"center", justifyContent:"center", flexDirection:"column", gap:"1rem" }}>
      <div className="spinner"/>
      <p style={{ color:"var(--muted)" }}>Completing sign in...</p>
    </div>
  );
}
